3291	\begin{lemma}
3292	[Naturality of the sheaf-level pullback--tensor comparison $\delta_{\mathrm{sheaf}}$ (D1$'$)]
3293	  \label{lem:pullback_tensor_map_natural}
3294	  \lean{AlgebraicGeometry.Scheme.Modules.pullbackTensorMap_natural}
3295	  \uses{lem:pullback_tensor_map, lem:presheaf_pullback_oplaxmonoidal}
3296	  Let \(f : Y \to X\) be a morphism of schemes. The sheaf-level comparison map
3297	  \(\delta_{\mathrm{sheaf}} = \mathtt{pullbackTensorMap}\) of
3298	  \cref{lem:pullback_tensor_map} is \emph{natural} in both module arguments: for
3299	  morphisms \(a : M \to M'\) and \(b : N \to N'\) in \(\Scheme.\mathtt{Modules}\,X\)
3300	  the square
3301	  \[
3302	    \begin{array}{ccc}
3303	      f^*(M \otimes_X N)
3304	        & \xrightarrow{\;\delta_{\mathrm{sheaf}}\;}
3305	        & f^*M \otimes_Y f^*N \\[2pt]
3306	      \big\downarrow{\scriptstyle f^*(a \otimes b)}
3307	        & & \big\downarrow{\scriptstyle f^*a \,\otimes\, f^*b} \\[4pt]
3308	      f^*(M' \otimes_X N')
3309	        & \xrightarrow{\;\delta_{\mathrm{sheaf}}\;}
3310	        & f^*M' \otimes_Y f^*N'
3311	    \end{array}
3312	  \]
3313	  commutes.
3314	\end{lemma}
3315	
3316	\begin{proof}
3317	  \uses{lem:pullback_tensor_map, lem:presheaf_pullback_oplaxmonoidal}
3318	  The map \(\delta_{\mathrm{sheaf}}\) is built (\cref{lem:pullback_tensor_map}) by
3319	  transporting the abstract oplax comparison \(\delta\) of the presheaf pullback
3320	  (\cref{lem:presheaf_pullback_oplaxmonoidal}) through the sheafification
3321	  reconciliations. Each ingredient is natural: the abstract oplax \(\delta\) is natural
3322	  in both arguments --- this is Mathlib's
3323	  \(\mathtt{Functor.OplaxMonoidal.}\delta\mathtt{\_natural}\), valid for any oplax
3324	  monoidal functor --- and the sheafification, the \(\mathtt{sheafificationCompPullback}\)
3325	  comparison, and the unit/tensor reconciliation \(\mathtt{sheafifyTensorUnitIso}\) are
3326	  natural transformations. The asserted square is the pasting of these naturality squares,
3327	  so it commutes; naturality in the two arguments is checked separately and then combined,
3328	  the tensor of the two component morphisms factoring as \(f^*a \otimes f^*b\) by
3329	  bifunctoriality of \(\otimes_Y\).
3330	\end{proof}
